repo.src/style.css:
:root {
  --bg: #0f172a;
  --bg-soft: #111f35;
  --card: #14243d;
  --text: #dbe7ff;
  --muted: #9cb1d8;
  --line: #294264;
  --good: #34d399;
  --warn: #f59e0b;
  --bad: #f87171;
  --brand: #60a5fa;
  --brand-soft: #1d4f94;
  --shadow: rgba(0, 0, 0, 0.25) 0 14px 24px -14px;
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, sans-serif;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  color: var(--text);
  background: radial-gradient(circle at 20% 20%, #132443, var(--bg) 45%);
  min-height: 100vh;
}

#app {
  min-height: 100vh;
}

.shell {
  display: grid;
  grid-template-columns: 260px 1fr;
  min-height: 100vh;
}

.sidebar {
  border-right: 1px solid var(--line);
  background: rgba(12, 27, 49, 0.75);
  padding: 24px 18px;
  position: sticky;
  top: 0;
  height: 100vh;
}

.sidebar h1 {
  margin: 0;
  font-size: 24px;
}

.sub {
  margin: 6px 0 24px;
  color: var(--muted);
  font-size: 14px;
  word-break: break-word;
}

.nav {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.nav-item {
  border: 1px solid transparent;
  color: var(--muted);
  background: transparent;
  text-align: left;
  padding: 10px 12px;
  border-radius: 10px;
  cursor: pointer;
  font-size: 14px;
}

.nav-item:hover,
.nav-item.active {
  color: var(--text);
  border-color: var(--brand-soft);
  background: rgba(37, 99, 235, 0.16);
}

.workspace {
  padding: 22px;
}

.topbar {
  display: flex;
  justify-content: space-between;
  gap: 14px;
  margin-bottom: 16px;
  align-items: flex-start;
}

.topbar h2 {
  margin: 0;
  font-size: 22px;
}

.topbar p {
  margin: 6px 0 0;
  color: var(--muted);
}

.meta-pill {
  margin-top: 10px;
  font-size: 13px;
  color: var(--brand);
}

.meta-pill.warn {
  color: var(--warn);
}

.meta-pill code {
  font-size: 12px;
  background: rgba(0, 0, 0, 0.25);
  padding: 1px 5px;
  border-radius: 4px;
}

.filters {
  display: flex;
  gap: 10px;
}

.filters label {
  display: flex;
  flex-direction: column;
  gap: 5px;
  color: var(--muted);
  font-size: 13px;
}

select {
  background: var(--bg-soft);
  border: 1px solid var(--line);
  color: var(--text);
  border-radius: 8px;
  padding: 8px;
}

button {
  background: rgba(37, 99, 235, 0.18);
  border: 1px solid var(--brand-soft);
  color: var(--text);
  border-radius: 8px;
  padding: 8px 11px;
  cursor: pointer;
  margin-right: 8px;
  margin-top: 10px;
}

button:hover {
  background: rgba(37, 99, 235, 0.32);
}

.kpi-grid {
  display: grid;
  gap: 12px;
  margin-bottom: 14px;
  grid-template-columns: repeat(4, minmax(0, 1fr));
}

.card {
  border: 1px solid var(--line);
  background: linear-gradient(180deg, rgba(20, 36, 61, 0.98), rgba(17, 30, 49, 0.98));
  border-radius: 14px;
  padding: 14px;
  box-shadow: var(--shadow);
}

.eyebrow {
  margin: 0 0 8px;
  color: var(--muted);
  font-size: 12px;
}

.value {
  margin: 0;
  font-size: 27px;
  font-weight: 700;
}

.delta {
  margin: 6px 0 0;
  font-weight: 600;
}

.positive {
  color: var(--good);
}

.negative {
  color: var(--bad);
}

.view {
  display: none;
  gap: 12px;
}

.view.show {
  display: grid;
}

.split {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
}

h3 {
  margin: 0 0 12px;
  font-size: 16px;
}

.funnel,
.alerts {
  list-style: none;
  padding: 0;
  margin: 0;
}

.funnel li,
.alerts li {
  display: flex;
  justify-content: space-between;
  padding: 10px 0;
  border-bottom: 1px dashed var(--line);
}

.alerts li {
  justify-content: flex-start;
  gap: 8px;
}

.alerts .ok::before {
  content: "OK";
  color: var(--good);
}

.alerts .warn::before {
  content: "!";
  color: var(--warn);
}

.chips {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.chip {
  background: rgba(59, 130, 246, 0.14);
  border: 1px solid var(--brand-soft);
  border-radius: 999px;
  padding: 6px 10px;
  font-size: 13px;
}

table {
  width: 100%;
  border-collapse: collapse;
}

th,
td {
  text-align: left;
  font-size: 13px;
  padding: 10px 8px;
  border-bottom: 1px solid var(--line);
}

th {
  color: var(--muted);
  font-weight: 500;
}

.loading {
  min-height: 100vh;
  display: grid;
  place-content: center;
  color: var(--text);
  font-size: 18px;
  text-align: center;
  padding: 20px;
}

.loading.error {
  color: var(--warn);
}

.json-box {
  margin-top: 12px;
  padding: 10px;
  border: 1px solid var(--line);
  border-radius: 10px;
  background: rgba(9, 18, 33, 0.65);
  color: #d1e3ff;
  font-size: 12px;
  line-height: 1.45;
  overflow: auto;
  max-height: 240px;
}

/* Meta-style ad preview */
.ad-preview-hero .ad-preview-layout,
.ad-preview-card-wrap .ad-preview-device {
  margin-top: 12px;
}

.ad-preview-layout {
  display: grid;
  grid-template-columns: minmax(0, 400px) minmax(260px, 1fr);
  gap: 24px;
  align-items: start;
}

.ad-preview-form {
  display: flex;
  flex-direction: column;
