            const existing = state.audiences.find((a) => a.segment === segment);
            if (existing) {
              existing.users = emails.length;
              existing.sync = "just now";
              existing.retries = 0;
              existing.status = "Healthy";
            } else {
              state.audiences.unshift({
                segment,
                users: emails.length,
