        });
        return;
      }

      if (req.method === "POST" && req.url === "/api/meta/capi/event") {
        const body = await parseBody(req);
        if (useMockMeta()) {
          sendJson(req, res, 200, {
            ok: true,
            metaMode: "mock",
            note: "META_USE_MOCK or missing token — CAPI not sent",
            wouldSend: body,
          });
