          const reconcile = mergeInsightsIntoCampaignRows(raw);
          for (const sample of reconcile.samples || []) {
            await upsertPerformanceSample(sample);
          }
          sendJson(req, res, 200, { ok: true, metaMode: "live", raw, reconcile });
