import { state } from "./state.js";

/**
 * Match Meta insights rows to local campaigns via metaAdsetId; update spend (platform-reported).
 */
export function mergeInsightsIntoCampaignRows(raw) {
  const rows = raw?.data;
  if (!Array.isArray(rows)) return { matched: 0, samples: [] };
  let matched = 0;
  const samples = [];
  for (const r of rows) {
    const adsetId = r.adset_id != null ? String(r.adset_id) : null;
    if (!adsetId) continue;
    const c = state.campaigns.find((row) => row.metaAdsetId && String(row.metaAdsetId) === adsetId);
    if (!c) continue;
    const spend = Number(r.spend ?? 0);
    if (!Number.isNaN(spend)) c.spend = spend;
    const impressions = Number(r.impressions ?? 0);
    if (!Number.isNaN(impressions)) c.impressions = impressions;
    const clicks = Number(r.clicks ?? 0);
    if (!Number.isNaN(clicks)) c.clicks = clicks;
    samples.push({
      metaAdsetId: adsetId,
      campaignName: c.campaign,
      adsetName: c.adset,
      spend,
      clicks: Number(r.clicks ?? 0),
      impressions: Number(r.impressions ?? 0),
    });
    matched += 1;
  }
  return { matched, samples };
}

repo.server/policy.js:
import { getMetaConfig, isMetaConfigured } from "./meta-graph.js";

/**
 * Publish / activate gates — conservative defaults.
 * Set META_AUTO_PUBLISH=true to allow auto-activation when checks pass.
 * trackingHealth is persisted (0–1) and updated from recent CAPI success rate when events are sent.
 */
export function evaluatePublishPolicy({ useMock, trackingHealth }) {
  const cfg = getMetaConfig();
  const reasons = [];

  if (!useMock) {
    if (process.env.META_AUTO_PUBLISH !== "true") {
      reasons.push("META_AUTO_PUBLISH is not true (set to enable auto-activate)");
    }
    if (!isMetaConfigured()) {
      reasons.push("Meta token/ad account not configured");
    }
    if (!cfg.pageId) {
      reasons.push("META_PAGE_ID required for live creatives");
    }
  }

  const th = Number(trackingHealth ?? 0.85);
  if (th < 0.65) {
    reasons.push(`tracking health ${th} below 0.65`);
  }

  const allowed = reasons.length === 0;
  return {
    allowed,
    reasons: allowed ? ["ready for auto-publish"] : reasons,
    config: {
      metaAutoPublish: process.env.META_AUTO_PUBLISH === "true",
      hasPage: Boolean(cfg.pageId),
      mockRelaxed: useMock,
    },
  };
}

