/** Simple in-memory sliding window rate limiter per client key (e.g. IP). */
const buckets = new Map();

export function rateLimitCheck(key, maxPerWindow = 120, windowMs = 60_000) {
  const now = Date.now();
  let b = buckets.get(key);
  if (!b || now > b.resetAt) {
    b = { count: 0, resetAt: now + windowMs };
    buckets.set(key, b);
  }
  b.count += 1;
  if (b.count > maxPerWindow) {
    return { ok: false, retryAfterSec: Math.ceil((b.resetAt - now) / 1000) };
  }
  return { ok: true };
}

export function clientKeyFromReq(req) {
  const xf = req.headers["x-forwarded-for"];
  if (typeof xf === "string" && xf.length) {
    return xf.split(",")[0].trim();
  }
  return req.socket?.remoteAddress || "local";
}

repo.server/webhook-verify.js:
import crypto from "node:crypto";

/**
 * Optional HMAC-SHA256 for CRM webhooks.
 * Header: X-Webhook-Signature: sha256=<hex>
 */
export function verifyCrmWebhookSignature(rawBody, signatureHeader, secret) {
  if (!secret) return true;
  if (!signatureHeader || typeof signatureHeader !== "string") return false;
  const prefix = "sha256=";
  if (!signatureHeader.startsWith(prefix)) return false;
  const got = signatureHeader.slice(prefix.length);
  const expected = crypto.createHmac("sha256", secret).update(rawBody, "utf8").digest("hex");
  const a = Buffer.from(got, "utf8");
  const b = Buffer.from(expected, "utf8");
  if (a.length !== b.length) return false;
  return crypto.timingSafeEqual(a, b);
}

